function showSequence(steps, finalCallback)
    local idx = 0
    local function next()
        idx = idx + 1
        if idx > #steps then
            if finalCallback then finalCallback() end
            return
        end
        local step = steps[idx]
        Wherigo.MessageBox{
            Text = step.Text,
            Media = step.Media,
            Callback = function(action)
                if step.Action then step.Action() end
                next()
            end
        }
    end
    next()
end

function showChoices(question, choices, inputObj)
    local letters = {"A", "B", "C", "D"}
    local lines = question
    for i, choice in ipairs(choices) do
        lines = lines .. [[

]] .. letters[i] .. ". " .. choice
    end
    inputObj.Text = lines
    Wherigo.GetInput(inputObj)
end

function weightedRandom(weights)
    local total = 0
    for _, w in ipairs(weights) do total = total + w end
    local r = math.random() * total
    local cumulative = 0
    for i, w in ipairs(weights) do
        cumulative = cumulative + w
        if r <= cumulative then return i end
    end
    return #weights
end

function makeZonePoints(lat, lon, radiusMeters)
    local latOff = radiusMeters / 111000
    local lonOff = radiusMeters / (111000 * math.cos(math.rad(lat)))
    return {
        ZonePoint(lat + latOff, lon - lonOff, 0),
        ZonePoint(lat + latOff, lon + lonOff, 0),
        ZonePoint(lat - latOff, lon + lonOff, 0),
        ZonePoint(lat - latOff, lon - lonOff, 0),
    }
end

function pick(tbl)
    return tbl[math.random(#tbl)]
end

