    selectedField = field
    setFieldCoordinates(field)
    zoneTunnel.Active = false
    zoneTunnel.Visible = false

    Wherigo.MessageBox{
        Text = ack,
        Callback = function() activateZoneOrEnterIfInside(zoneDugout) end,
    }
end

function loadRunnerStats(name)
    local p = playerDB[name]
    if not p then return end
    runnerPower = p.power
    runnerContact = p.contact
    runnerBunting = p.bunting
    runnerSpeed = p.speed
    runnerIQ = p.iq
end

function loadBatterStats(name)
    local p = playerDB[name]
    if not p then return end
    batterPower = p.power
    batterContact = p.contact
    batterBunting = p.bunting
    batterSpeed = p.speed
    batterIQ = p.iq
    batterStyle = p.style
end

function advanceBatterIndex()
    batterIndex = batterIndex + 1
    if batterIndex > #lineupOrder then
        batterIndex = 1
    end
    currentBatter = lineupOrder[batterIndex]
    loadBatterStats(currentBatter)
    balls = 0
    strikes = 0
    pitchNumber = 0
end

function getStatBonus()
    local bonus = 0
    if mooseMagicActive then bonus = bonus + 1 end
    return bonus
end

function getShortName(name)
    local p = playerDB[name]
    if p and p.short then return p.short end
    return name
end

function calculateScore(baseDifficulty, primaryStat, secondaryStat)
    local bonus = getStatBonus()
    local primary = primaryStat + bonus
    local secondary = math.floor((secondaryStat + bonus) / 2)
    local roll = math.random(1, 6)
    return baseDifficulty + primary + secondary + roll
end

function getResult(score)
    if score <= 4 then return "failure"
    elseif score <= 7 then return "partial"
    elseif score <= 10 then return "success"
    else return "big_success" end
end
