function handleSwingFailure(approach)
    if approach == "Contact swing" then
        local r = math.random(3)
        if r == 1 then
            strikes = strikes + 1
            if strikes >= 3 then
                handleRunnerOut("Strike three. You swing over a nasty breaking ball that drops out of the zone at the last second. The bat cuts through nothing but air.")
                return
            end
            Wherigo.MessageBox{
                Text = getContactFoulText(),
                Callback = function() showSwingPrompt() end,
            }
        else
            handleRunnerOut(getContactOutText())
        end
    elseif approach == "Power swing" then
        local r = math.random(2)
        if r == 1 then
            strikes = strikes + 1
            if strikes >= 3 then
                handleRunnerOut("Strike three! You uncork a massive swing and miss by a foot. The bat whips through the zone and the catcher squeezes the ball. The dugout goes quiet.")
                return
            end
            Wherigo.MessageBox{
                Text = getPowerMissText(),
                Callback = function() showSwingPrompt() end,
            }
        else
            handleRunnerOut(getPowerOutText())
        end
    else
        handleRunnerOut(getBuntOutText())
    end
end

