function resolvePitch()
    pitchNumber = pitchNumber + 1

    if runnerPlay == "steal" then
        resolveStealAttempt()
    elseif runnerPlay == "squeeze" then
        resolveSqueezePlay()
    else
        resolveStayAttempt()
    end
end

function resolveStealAttempt()
    stealFromBase = currentBase
    local leadBonus = 0
    if leadSize == "big" then leadBonus = 1
    elseif leadSize == "none" then leadBonus = -2 end

    local score = calculateScore(-2 + leadBonus, runnerSpeed, runnerIQ)
    local threshold = 6
    if currentBase == "third" then threshold = 8 end

    local dest = getNextBase()
    if score >= threshold then
        stealResult = "safe"
    else
        stealResult = "out"
    end

    needNewBatter = false
    local msg = pick({
        "You take off! Your legs drive hard as you sprint for " .. dest .. "!",
        "GO! You explode off the bag and race toward " .. dest .. "!",
        "You break for it! Full speed toward " .. dest .. "!",
        "The pitcher starts his motion and you're already gone! You fly toward " .. dest .. "!",
    })

    if dest == "home" then
        msg = msg .. [[

RUN HOME!]]
    else
        msg = msg .. [[

RUN TO ]] .. string.upper(dest) .. "!"
    end

    Wherigo.MessageBox{
        Text = msg,
        Callback = function() advanceReason = "steal" beginRunToBase(dest) end,
    }
end

function resolveSqueezePlay()
    local short = getShortName(currentBatter)
    local score = calculateScore(0, batterContact, batterIQ)
    if leadSize == "big" then score = score + 1 end

    if score >= 7 then
        squeezeResult = "safe"
    elseif score >= 4 then
        local outcomes = {"fielded", "popped", "hard_to_pitcher"}
        squeezeResult = outcomes[math.random(#outcomes)]
    else
        local outcomes = {"missed", "popped", "fielded", "hard_to_pitcher"}
        squeezeResult = outcomes[math.random(#outcomes)]
    end

    needNewBatter = true
    consecutiveBigLeads = 0

    local msg = pick({
        "You flash the squeeze sign. " .. short .. " nods from the box. The pitcher winds up and you break for home!",
        "Squeeze play! You take off the moment the pitcher starts his motion. " .. short .. " squares around to bunt. You're committed!",
        "You call for the squeeze. Everything is on the line. The pitcher delivers and you sprint for home plate!",
        "The squeeze is on! " .. short .. " shows bunt as the pitch comes in. You explode off third and charge for home!",
    })

    msg = msg .. [[

RUN HOME!]]

    Wherigo.MessageBox{
        Text = msg,
        Callback = function() advanceReason = "squeeze" beginRunToBase("home") end,
    }
end

function resolveStayAttempt()
    local attemptChance = 0
    if leadSize == "short" then
        if currentBase == "first" then attemptChance = 10
        elseif currentBase == "second" then attemptChance = 6
        else attemptChance = 3 end
    elseif leadSize == "big" then
        if currentBase == "first" then attemptChance = 30
        elseif currentBase == "second" then attemptChance = 20
        else attemptChance = 10 end
        attemptChance = attemptChance + (consecutiveBigLeads - 1) * 10
    end

    if math.random(100) <= attemptChance then
        local caughtChance = 50 - (runnerIQ * 5) - (runnerSpeed * 3)
        caughtChance = math.max(10, caughtChance)
        if leadSize == "short" then caughtChance = math.max(5, caughtChance - 15) end

        if math.random(100) <= caughtChance then
            local msg = pick({
                [[The pitcher suddenly spins and fires to the base! You dive back, but the tag is already there. The umpire pumps his fist.]] .. [[

OUT!]],
                [[Without warning, the pitcher snaps a throw to the bag! You scramble back but the fielder slaps the tag on your shoulder.]] .. [[

Out!]],
                [[The pitcher fakes toward home, then whirls and throws behind you! You were leaning the wrong way. The tag gets you.]] .. [[

Out!]],
            })
            if hasRallyCap and not itemUsed then
                offerRallyCap(msg)
            else
                handleRunnerOut(msg)
            end
            return
        else
            Wherigo.MessageBox{
                Text = pick({
                    "The pitcher whips a throw to the bag! You dive back just in time -- SAFE! The fielder slaps his glove in frustration. That was close. He's watching you.",
                    "Pickoff attempt! The pitcher fires to the base and you scramble back headfirst. The umpire spreads his arms -- safe! But your heart is pounding.",
                    "The pitcher suddenly spins and throws behind you! You lunge back to the bag and get your hand on it just before the tag. Safe -- but barely.",
                    "Without warning, the pitcher snaps a throw over! You hit the dirt and grab the base. Safe! The crowd gasps. He's got your number.",
                }),
                Callback = function() showPitchPrompt() end,
            }
            return
        end
    end

    batterApproach = chooseBatterApproach()
    pitchOutcome = determinePitchOutcome(batterApproach)
    handlePitchResult()
end

function chooseBatterApproach()
    local wTake = batterIQ * 2
    local wContact = batterContact * 2
    local wPower = batterPower * 2
    local wBunt = batterBunting

    if strikes == 2 then
        wPower = math.max(1, math.floor(wPower / 2))
        wContact = math.floor(wContact * 1.5)
        wBunt = math.max(1, math.floor(wBunt / 2))
    end
    if balls == 3 then
        wTake = wTake * 3
    end
    if balls >= 2 and strikes <= 1 then
        wTake = math.floor(wTake * 1.5)
    end
    if currentBase == "third" then
        wBunt = wBunt * 2
        wContact = math.floor(wContact * 1.5)
    end

    local approaches = {"take", "contact", "power", "bunt"}
    local weights = {
        math.max(1, wTake),
        math.max(1, wContact),
        math.max(1, wPower),
        math.max(1, wBunt),
    }
    return approaches[weightedRandom(weights)]
end

function determinePitchOutcome(approach)
    local r = math.random(100)
    if approach == "take" then
        local ballChance = 50 + batterIQ * 3
        if r <= ballChance then return "ball"
        elseif r <= 97 then return "called_strike"
        else return "wild_pitch" end
    elseif approach == "contact" then
        if r <= 15 then return "ball"
        elseif r <= 22 then return "called_strike"
        elseif r <= 30 then return "swinging_strike"
        elseif r <= 50 then return "foul"
        elseif r <= 95 then return "ball_in_play"
        else return "wild_pitch" end
    elseif approach == "power" then
        if r <= 15 then return "ball"
        elseif r <= 22 then return "called_strike"
        elseif r <= 45 then return "swinging_strike"
        elseif r <= 55 then return "foul"
        elseif r <= 95 then return "ball_in_play"
        else return "wild_pitch" end
    elseif approach == "bunt" then
        if r <= 10 then return "ball"
        elseif r <= 15 then return "called_strike"
        elseif r <= 25 then return "swinging_strike"
        elseif r <= 45 then return "foul"
        elseif r <= 95 then return "ball_in_play"
        else return "wild_pitch" end
    end
    return "ball"
end

function handlePitchResult()
    if pitchOutcome == "ball" then
        handleBall()
    elseif pitchOutcome == "called_strike" or pitchOutcome == "swinging_strike" then
        handleStrike()
    elseif pitchOutcome == "foul" then
        handleFoul()
    elseif pitchOutcome == "ball_in_play" then
        resolveBallInPlay()
    elseif pitchOutcome == "wild_pitch" then
        resolveWildPitch()
    end
end

function handleBall()
    balls = balls + 1
    if balls >= 4 then
        handleWalk()
        return
    end
    local short = getShortName(currentBatter)
    local msg = pick({
        short .. " watches a pitch sail outside. Ball " .. balls .. ". You stay put.",
        "The pitch dips low into the dirt. " .. short .. " doesn't chase. Ball " .. balls .. ".",
        short .. " lays off a breaking ball that misses the zone. Ball " .. balls .. ".",
        "The pitch drifts high. " .. short .. " holds up. Ball " .. balls .. ".",
    })
    Wherigo.MessageBox{
        Text = msg,
        Callback = function() showPitchPrompt() end,
    }
end

function handleStrike()
    strikes = strikes + 1
    local short = getShortName(currentBatter)
    if strikes >= 3 then
        handleBatterStrikeout()
        return
    end
    local msg = ""
    if pitchOutcome == "called_strike" then
        msg = pick({
            short .. " freezes as the pitch catches the outside corner. Strike " .. strikes .. " called.",
            "The umpire punches a called strike. " .. short .. " glances back but says nothing. Strike " .. strikes .. ".",
            "A fastball on the inside edge. " .. short .. " thought it was tight, but the ump calls it. Strike " .. strikes .. ".",
        })
    else
        msg = pick({
            short .. " swings and misses on a nasty breaking ball. Strike " .. strikes .. ".",
            short .. " takes a big hack and comes up empty. The ball dipped right under the bat. Strike " .. strikes .. ".",
            short .. " chases a pitch out of the zone and whiffs. Strike " .. strikes .. ".",
        })
    end
    Wherigo.MessageBox{
        Text = msg,
        Callback = function() showPitchPrompt() end,
    }
end

function handleFoul()
    if strikes < 2 then
        strikes = strikes + 1
    end
    local short = getShortName(currentBatter)
    local msg = pick({
        short .. " fouls one back to the screen. The crowd flinches. Count: " .. balls .. "-" .. strikes,
        short .. " gets the bat on it but chops it foul past third. Still alive. Count: " .. balls .. "-" .. strikes,
        "A foul ball off the bat of " .. short .. " -- a lazy pop that drifts into the stands. Count: " .. balls .. "-" .. strikes,
        short .. " fights one off, sending a sharp foul into the dugout. The at-bat continues. Count: " .. balls .. "-" .. strikes,
    })
    Wherigo.MessageBox{
        Text = msg,
        Callback = function() showPitchPrompt() end,
    }
end

function handleWalk()
    local short = getShortName(currentBatter)

    local firstOccupied = runnerOnFirst or (currentBase == "first")
    local secondOccupied = runnerOnSecond or (currentBase == "second")
    local thirdOccupied = (currentBase == "third")

    if firstOccupied and secondOccupied and thirdOccupied then
        runnerOnFirst = true
        runnerOnSecond = true
        Wherigo.MessageBox{
            Text = "Ball four! " .. short .. [[ takes the free pass and the bases were loaded! You're forced home! This is a walk-off walk!

Run to home plate!]],
            Callback = function() advanceReason = "walk" beginRunToBase("home") end,
        }
    elseif firstOccupied and (currentBase == "first") then
        runnerOnFirst = true
        Wherigo.MessageBox{
            Text = "Ball four! " .. short .. [[ flips the bat and jogs to first. The pitcher missed his spot and now the bases are getting crowded. You're forced to move up.

Run to second base!]],
            Callback = function() advanceReason = "walk" beginRunToBase("second") end,
        }
    elseif firstOccupied and secondOccupied and (currentBase == "second") then
        runnerOnFirst = true
        runnerOnSecond = true
        Wherigo.MessageBox{
            Text = "Ball four! " .. short .. [[ takes first and the runners move up. With first and second occupied, you're forced to third!

Run to third base!]],
            Callback = function() advanceReason = "walk" beginRunToBase("third") end,
        }
    else
        if runnerOnFirst then
            runnerOnSecond = true
        end
        runnerOnFirst = true
        Wherigo.MessageBox{
            Text = "Ball four! " .. short .. " draws the free pass and trots to first. The crowd claps -- the lineup is doing its job, keeping the pressure on. You hold your base.",
            Callback = function()
                advanceBatterIndex()
                showPitchPrompt()
            end,
        }
    end
end

function handleBatterStrikeout()
    outs = outs + 1
    local short = getShortName(currentBatter)
    local msg = pick({
        "Strike three! " .. short .. " swings through a fastball up in the zone. The bat comes around too late. The dugout groans.",
        "Strike three called! " .. short .. " was looking for something offspeed, but the pitcher blew a heater right by. The umpire rings the bell.",
        "Strike three! " .. short .. " chases a slider in the dirt. The catcher scoops it and the umpire punches the out.",
    })
    msg = msg .. [[

Outs: ]] .. outs
    if outs >= 3 then
        handleGameLoss(msg .. [[

Three outs. The side is retired.]])
    else
        Wherigo.MessageBox{
            Text = msg,
            Callback = function()
                advanceBatterIndex()
                showPitchPrompt()
            end,
        }
    end
end

function resolveBallInPlay()
    local baseDiff = 0
    local primaryStat = batterContact
    local secondaryStat = batterIQ

    if batterApproach == "power" then
        baseDiff = -1
        primaryStat = batterPower
        secondaryStat = batterContact
    elseif batterApproach == "bunt" then
        primaryStat = batterBunting
        secondaryStat = batterIQ
    end

    local score = calculateScore(baseDiff, primaryStat, secondaryStat)
    local result = getResult(score)

    if result == "failure" then
        resolveBIPOut()
    elseif result == "partial" then
        resolveBIPPartial()
    elseif result == "success" then
        resolveBIPHit("single")
    else
        resolveBIPHit("double")
    end
end

function resolveBIPOut()
    outs = outs + 1
    local short = getShortName(currentBatter)

    if currentBase == "third" and batterPower >= 3 then
        local tagScore = calculateScore(-1, runnerSpeed, runnerIQ)
        if tagScore >= 7 then
            local msg = short .. " gets under a fastball and launches a towering fly ball to deep left field. The outfielder drifts back... back... makes the catch at the warning track. Out " .. outs .. "."
            if outs >= 3 then
                handleGameLoss(msg .. [[

Three outs. The inning is over.]])
                return
