    else
        msg = pick({
            short .. " chops a grounder to short. The shortstop fields it cleanly, plants, and throws a seed to first. Out.",
            short .. " rolls a soft grounder to second. The second baseman charges, gloves it, and flips to first in one motion.",
            short .. " hits a sharp one-hopper right at the third baseman. He snares it and rifles a throw across the diamond. Out at first.",
        })
    end
    msg = msg .. [[

Outs: ]] .. outs

    if outs >= 3 then
        handleGameLoss(msg .. [[

Three outs. The inning is over.]])
    else
        Wherigo.MessageBox{
            Text = msg,
            Callback = function()
                advanceBatterIndex()
                showPitchPrompt()
            end,
