    if strikes < 2 then strikes = strikes + 1 end
    Wherigo.MessageBox{
        Text = pick({
            short .. [[ fights one off, sending a sharp foul down the line. Still battling.

Count: ]] .. balls .. "-" .. strikes,
            short .. [[ gets a piece of it and fouls it straight back. You hold your base.

Count: ]] .. balls .. "-" .. strikes,
