function resolveBIPHit(hitType)
    local dest = getNextBase()
    local short = getShortName(currentBatter)

    if hitType == "double" and currentBase ~= "third" then
        extraBasesToRun = 1
    end

    advanceRunners(hitType == "double" and 2 or 1)
    if hitType == "double" then
        runnerOnSecond = true
    else
        runnerOnFirst = true
    end

    local msg = getBatterHitText(short, batterApproach == "bunt") .. getBatterFlavor(short)

    if dest == "home" then
        msg = msg .. [[ The third base coach is windmilling his arm -- GO! GO! GO!

RUN HOME!]]
    else
        msg = msg .. [[ You're moving up!

RUN TO ]] .. string.upper(dest) .. "!"
    end

    Wherigo.MessageBox{
        Text = msg,
        Callback = function() advanceReason = "hit" beginRunToBase(dest) end,
    }
end

function resolveWildPitch()
    balls = balls + 1
    local advScore = calculateScore(1, runnerSpeed, runnerIQ)

    if advScore >= 6 then
        local dest = getNextBase()
        advanceRunners(1)
        local msg = ""
        if dest == "home" then
            msg = [[Wild pitch! The ball skips off the dirt and bounces away from the catcher! It rolls all the way to the backstop! This is your chance -- GO!

RUN HOME!]]
        else
            msg = [[Wild pitch! The ball skips past the catcher and bounces toward the backstop! You see it happen in real time -- the catcher lunging, the ball squirting away. You take off!

RUN TO ]] .. string.upper(dest) .. "!"
        end
        needNewBatter = false
        Wherigo.MessageBox{
            Text = msg,
            Callback = function() advanceReason = "wild_pitch" beginRunToBase(dest) end,
        }
    else
        if balls >= 4 then
            handleWalk()
        else
            Wherigo.MessageBox{
                Text = "Wild pitch! The ball kicks off the dirt, but the catcher blocks it with his chest protector and smothers it. You bluff a move but stay put. Ball " .. balls .. ".",
                Callback = function() showPitchPrompt() end,
            }
        end
    end
end

