    else
        return [[You were charging home, legs burning, but the throw beat you there. The catcher put the tag down and the umpire called you out.]] .. [[

So close.]]
    end
end

function getNextBase()
    if currentBase == "home" then return "first"
    elseif currentBase == "first" then return "second"
    elseif currentBase == "second" then return "third"
    elseif currentBase == "third" then return "home"
    end
    return "first"
end

function getZoneForBase(base)
    if base == "home" then return zoneHomePlate
    elseif base == "first" then return zoneFirstBase
    elseif base == "second" then return zoneSecondBase
    elseif base == "third" then return zoneThirdBase
    elseif base == "dugout" then return zoneDugout
    end
    return zoneHomePlate
end

function deactivateAllBaseZones()
    zoneHomePlate.Active = false
    zoneHomePlate.Visible = false
    zoneFirstBase.Active = false
    zoneFirstBase.Visible = false
    zoneSecondBase.Active = false
    zoneSecondBase.Visible = false
    zoneThirdBase.Active = false
    zoneThirdBase.Visible = false
end

