inputSelectPlayer.OnGetInput = function(input, answer)
    selectedPlayer = answer
    loadRunnerStats(answer)
    local p = playerDB[answer]

    remainingPlayers = {}
    for _, name in ipairs(playerNames) do
        if name ~= answer then
            table.insert(remainingPlayers, name)
        end
    end

    Wherigo.MessageBox{
        Text = selectedPlayer .. [[! My oh my, that's a fabulous choice.

]] .. p.selectionIntro .. [[

Now set your batting order. These are the players who will bat behind you while you try to score. Put your best hitters where you need them most.]],
        Callback = function() pickNextLineupSlot() end,
    }
end

function pickNextLineupSlot()
    if #remainingPlayers <= 1 then
        if #remainingPlayers == 1 then
            table.insert(lineupOrder, remainingPlayers[1])
        end
        lineupSet = true
        showLineupSummary()
        return
    end
    local slot = #lineupOrder + 2
    local text = "Pick batter #" .. slot .. [[:]]
    for _, name in ipairs(remainingPlayers) do
        text = text .. [[

]] .. name .. " -- " .. playerDB[name].desc
    end
    inputLineup.Text = text
    inputLineup.Choices = {}
    for _, name in ipairs(remainingPlayers) do
        table.insert(inputLineup.Choices, name)
    end
    Wherigo.GetInput(inputLineup)
end

inputLineup.OnGetInput = function(input, answer)
    table.insert(lineupOrder, answer)
    local newPool = {}
    for _, name in ipairs(remainingPlayers) do
        if name ~= answer then
            table.insert(newPool, name)
        end
    end
    remainingPlayers = newPool
    pickNextLineupSlot()
end

function showLineupSummary()
    local msg = [[You gotta love these guys. Your lineup is set:

1. ]] .. selectedPlayer .. [[ (you)]]
    for i, name in ipairs(lineupOrder) do
        msg = msg .. [[
]] .. (i + 1) .. [[. ]] .. name
    end
    Wherigo.MessageBox{
        Text = msg,
        Callback = function() startDugoutTrivia() end,
    }
end

function pickTriviaQuestion()
    if #triviaQuestions == 0 then return nil end

    local available = {}
    for i = 1, #triviaQuestions do
        local seen = false
        for _, s in ipairs(triviaQuestionsSeen) do
            if s == i then seen = true end
        end
        if not seen then table.insert(available, i) end
    end
    if #available == 0 then
        -- All questions seen across this and prior playthroughs. Reset and refill.
        triviaQuestionsSeen = {}
        for i = 1, #triviaQuestions do
            table.insert(available, i)
        end
    end
    if #available == 0 then
        table.insert(triviaQuestionsSeen, 1)
        return triviaQuestions[1]
    end
    local qIdx = available[math.random(#available)]
    table.insert(triviaQuestionsSeen, qIdx)
    return triviaQuestions[qIdx]
end

function checkTriviaAnswer(tq, answer)
    local letters = {"A", "B", "C", "D"}
    for i, choice in ipairs(tq.choices) do
        if answer == letters[i] and choice == tq.answer then
            return true
        end
    end
    return false
end

