inputLeadSize.OnGetInput = function(input, answer)
    if answer == "No lead" then
        leadSize = "none"
        consecutiveBigLeads = 0
    elseif answer == "Short lead" then
        leadSize = "short"
        consecutiveBigLeads = 0
    else
        leadSize = "big"
        consecutiveBigLeads = consecutiveBigLeads + 1
    end
    askStealOrStay()
end

inputRunnerPlay.OnGetInput = function(input, answer)
    if answer == "Try to steal" then
        runnerPlay = "steal"
    elseif answer == "Call for a squeeze play" then
        runnerPlay = "squeeze"
    else
        runnerPlay = "stay"
    end
    resolvePitch()
