zoneHomePlate.OnEnter = function()
    if gameWon or gameLost then return end

    if runnerInTransit then
        local inTime = isRunnerSafe("home")
        if not inTime then
            handleRunnerOut(getRunnerOutMsg(advanceReason, "home"))
            return
        end
        if advanceReason == "steal" then
            if stealResult == "out" then
                stealResult = ""
                local msg = generateStealFailMsg()
                if hasRallyCap and not itemUsed then
                    offerRallyCap(msg)
                else
                    handleRunnerOut(msg)
                end
                return
            end
            stealResult = ""
        end
        if advanceReason == "squeeze" then
            local result = squeezeResult
            squeezeResult = ""
            if result ~= "safe" then
                local msg = generateSqueezeFailMsg(result)
                if hasRallyCap and not itemUsed then
                    offerRallyCap(msg)
                else
                    handleRunnerOut(msg)
                end
                return
            end
        end
        handleGameWin()
        return
    end

    -- guard against iOS re-firing OnEnter after backgrounding
    if currentBase == "home" then return end

    if currentBase == "dugout" then
        currentBase = "home"
        startHomePlateAtBat()
    end
end

